+#[inline]
+fn write_u32_dec(buf: &mut [u8], mut n: u32) -> usize {
+    let mut rev = [0u8; 10];
+    let mut len = 0usize;
+
+    loop {
+        rev[len] = (n % 10) as u8;
+        len += 1;
+        n /= 10;
+        if n == 0 {
+            break;
+        }
+    }
+
+    for i in 0..len {
+        buf[i] = b'0' + rev[len - 1 - i];
+    }
+
+    len
+}
